import { debounce } from '@src/utils/mx-utils';
import { Component, Host, h, Prop, EventEmitter, Event, Watch, Listen } from '@stencil/core';

@Component({
  tag: 'mx-section-accordion',
  styleUrl: 'mx-section-accordion.css',
  shadow: false
})
export class MxSectionAccordion {

  /** Sets width of accordion. */
  @Prop() readonly width: string = '100%';

  /** Sets title of accordion. */
  @Prop() readonly titleText: string;

  /** Sets whether the accordion title is in compact form or not. */
  @Prop() readonly compact: boolean;

  /** Sets expanded prop of accordion. */
  @Prop({ mutable: true }) expanded: boolean;

  /** Sets count for badge. */
  @Prop() readonly badgeCount?: number;

  /** Sets whether to show badge count or not when accordion is expanded. */
  @Prop() readonly hideBadgeOnExpand: boolean;

  /** Sets whether to show slotted tag/icon  or not when accordion is expanded. */
  @Prop() readonly hideSlotTagIconOnExpand: boolean;

  @Watch('expanded')
  handleExpandedChange(newOpen: boolean) {
    this.expanded = newOpen;
  }

  /** This event is emitted to toggle the accordion. */
  @Event() accordionToggled: EventEmitter<boolean>;

  private accordionElement: HTMLDivElement;
  private accordionElementWrapper: HTMLDivElement;
  private resizeObserver: ResizeObserver;
  private elementObserver: MutationObserver;

  /** Offset used when using the wrapper height for height calculation */
  private readonly HEIGHT_BUFFER_SIZE = 16;

  @Listen('dropdownOpenRendered')
  @Listen('dropdownCloseRendered')
  recalculateHeight() {
    this.setExpandedAccordionHeight();
  }

  componentDidLoad() {
    // Note Missing IE support, has edge.
    this.resizeObserver = new ResizeObserver(() => {
      this.setExpandedAccordionHeight();
    });
    this.elementObserver = new MutationObserver((mutationsList) => {
      for (const mutation of mutationsList) {
        if (mutation.type === 'childList') {
          this.debouncedSetExpandedAccordionHeight();
          break;
        }
      }
    });
    this.resizeObserver.observe(this.accordionElementWrapper);
    this.elementObserver.observe(this.accordionElementWrapper, { childList: true, subtree: true });

  }

  disconnectedCallback() {
    this.resizeObserver.disconnect();
    this.elementObserver.disconnect();
  }


  private readonly toggleAccordion = (event: MouseEvent) => {
    event.preventDefault();
    this.expanded = !this.expanded;
    if (this.expanded) {
      this.calculateHeight();
    }
    this.accordionToggled.emit(this.expanded);
  };

  private readonly setExpandedAccordionHeight = () => {
    if (this.expanded) {
      this.accordionElement.style.transition = 'none';
      const expandedHeight = this.accordionElementWrapper.scrollHeight;
      this.accordionElement.setAttribute('style', `height: ${expandedHeight + this.HEIGHT_BUFFER_SIZE}px`);
    }
  };

  private readonly debouncedSetExpandedAccordionHeight = debounce(this.setExpandedAccordionHeight, 100);

  private readonly calculateHeight = () => {
    this.setExpandedAccordionHeight();
    this.resizeObserver.observe(this.accordionElementWrapper);
  };

  private shouldShowBadge(): boolean {
    return (
      typeof this.badgeCount === 'number' &&
      !isNaN(this.badgeCount) &&
      (!this.expanded || !this.hideBadgeOnExpand)
    );
  }

  private shouldShowSlotIcon(): boolean {
    return !this.hideSlotTagIconOnExpand || !this.expanded;
  }

  render() {
    return (
      <Host>
        <div style={{ width: this.width }}>
          <button style={{ width: this.width }}
            class={{
              'flex items-center justify-between': true,
              'heading-s border-t border-neutral-least-subtle bg-neutral-more-subtle': true,
              'hover:bg-neutral-less-subtle': true,
              'focus:border-neutral-least-subtle': true,
              'pl-16 pr-16': true,
              'h-32 py-4': this.compact,
              'h-40 py-8': !this.compact,
              'accordion-header': true
            }}
            aria-expanded={this.expanded}
            onClick={this.toggleAccordion}
          >
            <div class='flex items-center min-w-0'>
              <kds-icon-chevron-down
                size='s'
                class={{
                  'mx-kds-icon': true,
                  'up-arrow': this.expanded
                }}
              />
              <span class='kds-Heading--s accordion-title truncate pl-16' title={this.titleText}>
                {this.titleText}
              </span>

              <span class='title-icon-slot-container'
                style={{ display: this.shouldShowSlotIcon() ? 'inline-flex' : 'none' }}>
                <slot name='title-icon' />
              </span>
            </div>

            {this.shouldShowBadge() && (
              <div class='pl-16 flex items-center'>
                <kds-badge
                  count={this.badgeCount}
                  palette='brand'
                  kind='prominent'
                />
              </div>
            )}
          </button>
          <div
            class={{
              'overflow-hidden my-8 accordion-section': true,
              open: this.expanded
            }}
            aria-labelledby='accordion-header'
            ref={(ref) => (this.accordionElement = ref)}
            style={{ height: this.expanded ? `${this.accordionElement?.scrollHeight}px` : '0' }}
          >
            <div ref={(ref) => (this.accordionElementWrapper = ref)} class='accordion-section-wrapper'>
              <slot></slot>
            </div>
          </div>
        </div>
      </Host>
    );
  }
}
